class RandomizedCollection:
    def __init__(self):
        self.nums = []; self.pos = collections.defaultdict(set)
    def insert(self, val):
        self.pos[val].add(len(self.nums)); self.nums.append(val); return len(self.pos[val]) == 1
    def remove(self, val):
        if not self.pos[val]: return False
        idx = self.pos[val].pop(); last = self.nums[-1]
        self.nums[idx] = last
        self.pos[last].add(idx); self.pos[last].remove(len(self.nums)-1)
        self.nums.pop(); return True
    def getRandom(self):
        return random.choice(self.nums)

